// Aggregate all data for Claude
const newProperties = $('Supabase — Novas Propriedades 24h').all().map(i => i.json);
const priceReductions = $('Supabase — Reduções de Preço 24h').all().map(i => i.json);
const pipelineMetrics = $('Supabase — Pipeline Metrics').all().map(i => i.json);
const atRiskDeals = $('Supabase — Deals em Risco').all().map(i => i.json);

// Calculate pipeline totals
const totalWeightedGCI = pipelineMetrics.reduce((sum, s) => sum + (parseFloat(s.weighted_gci) || 0), 0);
const totalDeals = pipelineMetrics.reduce((sum, s) => sum + parseInt(s.deal_count), 0);
const totalPipelineValue = pipelineMetrics.reduce((sum, s) => sum + (parseFloat(s.total_value) || 0), 0);

// Top opportunities (score > 70)
const topOpportunities = newProperties
  .filter(p => p.opportunity_score > 70)
  .slice(0, 5);

// Format date
const today = new Date();
const dateStr = today.toLocaleDateString('pt-PT', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const aggregated = {
  date: today.toISOString().split('T')[0],
  date_formatted: dateStr,
  new_properties_count: newProperties.length,
  price_reductions_count: priceReductions.length,
  top_opportunities: topOpportunities,
  top_price_reductions: priceReductions.slice(0, 5),
  pipeline_metrics: pipelineMetrics,
  at_risk_deals: atRiskDeals,
  totals: {
    weighted_gci: Math.round(totalWeightedGCI),
    total_deals: totalDeals,
    total_pipeline_value: Math.round(totalPipelineValue)
  }
};

return [{ json: aggregated }];

