// Format report for email HTML
const reportText = $input.first().json.text || $input.first().json.content?.[0]?.text || 'Relatório não disponível';
const aggregated = $('Code — Agregar Dados').item.json;

// Convert line breaks to HTML
const htmlReport = reportText
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>')
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/^/, '<p>')
  .replace(/$/, '</p>');

// WhatsApp summary (first 2 lines + key metric)
const lines = reportText.split('\n').filter(l => l.trim());
const waSummary = `📊 Daily Brief ${aggregated.date}\n${lines[0]}\nGCI Pipeline: €${(aggregated.totals.weighted_gci/1000).toFixed(0)}K | Risco: ${aggregated.at_risk_deals.length} deals`.slice(0, 300);

return [{
  json: {
    report_text: reportText,
    report_html: htmlReport,
    whatsapp_summary: waSummary,
    date: aggregated.date,
    date_formatted: aggregated.date_formatted,
    totals: aggregated.totals,
    at_risk_count: aggregated.at_risk_deals.length,
    new_properties_count: aggregated.new_properties_count
  }
}];
